### TypeScript

```typescript
interface User {
    name: string;
    city: string;
    active: boolean;
}

const greet = (user: User): string => {
    return `Hello ${user.name} from ${user.city}!`;
};

const mic: User = {
    name: "Mic",
    city: "Quezon City",
    active: true
};

console.log(greet(mic));
```

